import sys
from pathlib import Path

# Add backend directory to path to allow absolute prefix-free imports
backend_path = str(Path(__file__).resolve().parents[1] / "backend")
if backend_path not in sys.path:
    # Add backend path after existing entries so top-level packages (e.g., root `models`)
    # are resolved first. Inserting at position 0 caused conflicts where
    # `backend/models` shadowed the project's root `models` package.
    sys.path.append(backend_path)

import logging
import redis
from flask import Flask, send_from_directory
from flask_cors import CORS
from flask_limiter import Limiter
from flask_limiter.util import get_remote_address
from flask_jwt_extended import JWTManager

from config.config import settings
from services.cache import CacheClient
from services.db import DatabaseService
from services.auth import AuthService
from services.logging_service import configure_logging
from api.blueprints import register_blueprints
from backend.auth.blueprints import auth_bp

FRONTEND_DIR = Path(__file__).resolve().parents[1] / "frontend"


def create_app() -> Flask:
    configure_logging()
    app = Flask(__name__, static_folder=None)
    CORS(
        app,
        resources={
            r"/api/*": {"origins": "*"},
            r"/auth/*": {"origins": "*"},
        },
        supports_credentials=True,
        allow_headers=["Content-Type", "Authorization"],
    )
    app.config["SECRET_KEY"] = settings.SECRET_KEY
    app.config["JWT_SECRET_KEY"] = settings.JWT_SECRET
    app.config["JSON_SORT_KEYS"] = False

    limiter_storage = "memory://"
    if settings.REDIS_URL:
        try:
            redis.Redis.from_url(settings.REDIS_URL).ping()
            limiter_storage = settings.REDIS_URL
        except Exception:
            logger = logging.getLogger(__name__)
            logger.warning("redis_unavailable_for_rate_limiting; falling back to memory storage")

    limiter = Limiter(
        key_func=get_remote_address,
        default_limits=[settings.RATE_LIMIT],
        storage_uri=limiter_storage,
    )
    limiter.init_app(app)

    JWTManager(app)
    app.cache = CacheClient(settings.REDIS_URL)
    app.db = DatabaseService(settings.DATABASE_URL)
    app.db.ensure_default_admin(settings.DEFAULT_ADMIN_EMAIL, AuthService.hash_password(settings.DEFAULT_ADMIN_PASSWORD))

    register_blueprints(app)
    
    # Register auth blueprint for /auth routes
    app.register_blueprint(auth_bp, url_prefix="/auth")

    @app.route("/", methods=["GET"])
    def serve_frontend():
        if (FRONTEND_DIR / "out" / "index.html").exists():
            return send_from_directory(FRONTEND_DIR / "out", "index.html")
        return send_from_directory(FRONTEND_DIR, "index.html")

    @app.route("/static/<path:filename>")
    def serve_static(filename):
        if (FRONTEND_DIR / "out" / filename).exists():
            return send_from_directory(FRONTEND_DIR / "out", filename)
        return send_from_directory(FRONTEND_DIR, filename)

    @app.errorhandler(400)
    def bad_request(error):
        return {"error": str(error)}, 400

    @app.errorhandler(401)
    def unauthorized(error):
        return {"error": str(error)}, 401

    @app.errorhandler(403)
    def forbidden(error):
        return {"error": str(error)}, 403

    @app.errorhandler(404)
    def not_found(error):
        return {"error": str(error)}, 404

    @app.errorhandler(500)
    def internal_error(error):
        logging.exception(error)
        return {"error": "Internal server error"}, 500

    return app

"""
Auth Blueprint - Complete role-based JWT authentication system
Supports ADMIN and CLIENT roles with secure token management
"""

from flask import Blueprint, request, jsonify, current_app
from werkzeug.exceptions import BadRequest, Unauthorized
from auth.jwt import JWTService
from services.auth import AuthService
from services.db import DatabaseService
from utils.validation import parse_request_json
from config.config import settings
from services.logging_service import get_logger

logger = get_logger(__name__)
auth_bp = Blueprint("auth", __name__)


def get_db() -> DatabaseService:
    """Get database service - prefer app instance"""
    return current_app.db if hasattr(current_app, "db") else DatabaseService(settings.DATABASE_URL)


def json_error(error):
    """Format error response"""
    import traceback
    traceback.print_exc()
    status = 401 if isinstance(error, Unauthorized) else 400 if isinstance(error, (BadRequest, ValueError)) else 500
    message = str(error) if isinstance(error, (BadRequest, ValueError, Unauthorized)) else f"Internal server error: {str(error)}"
    return jsonify({"error": message}), status


def require_user():
    """Extract user from Authorization header"""
    auth_header = request.headers.get("Authorization", "")
    if not auth_header.startswith("Bearer "):
        raise Unauthorized("Missing or invalid token")

    token = auth_header.split(" ", 1)[1]
    payload = JWTService.decode_access_token(token)
    if not payload:
        raise Unauthorized("Invalid or expired token")

    user = get_db().get_user_by_email(payload["sub"])
    if not user:
        raise Unauthorized("User not found")

    return user


def require_admin():
    """Ensure user is admin"""
    user = require_user()
    if user.get("role") != "admin":
        raise Unauthorized("Admin access required")
    return user


# ============ PUBLIC ROUTES ============

@auth_bp.route("/register", methods=["POST"])
def register():
    """Register new client user"""
    try:
        data = parse_request_json(request)
        email = data.get("email", "").strip().lower()
        password = data.get("password", "")

        if not email or not password:
            raise BadRequest("Email and password are required")

        if get_db().get_user_by_email(email):
            raise BadRequest("User already exists")

        password_hash = AuthService.hash_password(password)
        user = get_db().create_user(email, password_hash, "client")
        
        logger.info(f"New client registered: {email}")
        return jsonify({
            "message": "Registration successful",
            "user_id": user.get("id"),
            "email": email,
            "role": "client"
        }), 201
    except Exception as e:
        return json_error(e)


@auth_bp.route("/login", methods=["POST"])
def login():
    """Login and return JWT tokens"""
    try:
        data = parse_request_json(request)
        email = data.get("email", "").strip().lower()
        password = data.get("password", "")

        if not email or not password:
            raise BadRequest("Email and password are required")

        user = get_db().get_user_by_email(email)
        if not user or not AuthService.verify_password(password, user.get("password_hash", "")):
            raise Unauthorized("Invalid email or password")

        # Create tokens with role in claims
        access_token = JWTService.create_access_token(email)
        refresh_token = JWTService.create_refresh_token(email)

        logger.info(f"Login successful: {email} (role: {user.get('role', 'user')})")

        return jsonify({
            "token": access_token,
            "refresh_token": refresh_token,
            "user": {
                "id": user.get("id"),
                "email": user.get("email"),
                "role": user.get("role", "user"),
                "plan_tier": user.get("plan_tier", "free"),
                "created_at": user.get("created_at")
            }
        }), 200
    except Exception as e:
        return json_error(e)


@auth_bp.route("/refresh", methods=["POST"])
def refresh():
    """Refresh access token"""
    try:
        auth_header = request.headers.get("Authorization", "")
        if not auth_header.startswith("Bearer "):
            raise Unauthorized("Missing or invalid refresh token")

        token = auth_header.split(" ", 1)[1]
        payload = JWTService.decode_refresh_token(token)
        if not payload:
            raise Unauthorized("Invalid or expired refresh token")

        user = get_db().get_user_by_email(payload["sub"])
        if not user:
            raise Unauthorized("User not found")

        access_token = JWTService.create_access_token(user["email"])
        refresh_token = JWTService.create_refresh_token(user["email"])

        return jsonify({
            "token": access_token,
            "refresh_token": refresh_token
        }), 200
    except Exception as e:
        return json_error(e)


# ============ PROTECTED ROUTES ============

@auth_bp.route("/me", methods=["GET"])
def me():
    """Get current user info"""
    try:
        return jsonify({"user": require_user()}), 200
    except Exception as e:
        return json_error(e)


@auth_bp.route("/logout", methods=["POST"])
def logout():
    """Logout (client-side token removal)"""
    try:
        user = require_user()
        logger.info(f"Logout: {user.get('email')}")
        return jsonify({"message": "Logout successful"}), 200
    except Exception as e:
        return json_error(e)


# ============ ADMIN ROUTES ============

@auth_bp.route("/admins", methods=["GET"])
def list_admins():
    """List all admins"""
    try:
        require_admin()
        users = get_db().list_users()
        admins = [u for u in users if u.get("role") == "admin"]
        return jsonify({"admins": admins}), 200
    except Exception as e:
        return json_error(e)


@auth_bp.route("/admins", methods=["POST"])
def create_admin():
    """Create new admin"""
    try:
        require_admin()
        data = parse_request_json(request)
        email = data.get("email", "").strip().lower()
        password = data.get("password", "")

        if not email or not password:
            raise BadRequest("Email and password are required")
        
        if len(password) < 8:
            raise BadRequest("Password must be at least 8 characters")

        if get_db().get_user_by_email(email):
            raise BadRequest("User already exists")

        user = get_db().create_user(email, AuthService.hash_password(password), "admin")
        logger.info(f"New admin created: {email}")
        
        return jsonify({"user": user}), 201
    except Exception as e:
        return json_error(e)


@auth_bp.route("/users", methods=["GET"])
def list_users():
    """List all users (admin only)"""
    try:
        require_admin()
        users = get_db().list_users()
        return jsonify({"users": users}), 200
    except Exception as e:
        return json_error(e)


@auth_bp.route("/users/<int:user_id>/role", methods=["PUT"])
def update_user_role(user_id: int):
    """Update user role"""
    try:
        require_admin()
        data = parse_request_json(request)
        role = data.get("role", "").strip().lower()

        if role not in ["admin", "client"]:
            raise BadRequest("Role must be 'admin' or 'client'")

        get_db().update_user_role(user_id, role)
        logger.info(f"User {user_id} role changed to {role}")
        
        return jsonify({"message": f"User role updated to {role}"}), 200
    except Exception as e:
        return json_error(e)


@auth_bp.route("/users/<int:user_id>/plan", methods=["PUT"])
def update_user_plan(user_id: int):
    """Update user plan"""
    try:
        require_admin()
        data = parse_request_json(request)
        plan_tier = data.get("plan_tier", "").strip().lower()

        valid_plans = ["free", "pro", "enterprise", "unlimited"]
        if plan_tier not in valid_plans:
            raise BadRequest(f"Plan must be one of: {', '.join(valid_plans)}")

        get_db().update_user_plan(user_id, plan_tier)
        logger.info(f"User {user_id} plan changed to {plan_tier}")
        
        return jsonify({"message": f"User plan updated to {plan_tier}"}), 200
    except Exception as e:
        return json_error(e)


@auth_bp.route("/users/<int:user_id>", methods=["DELETE"])
def delete_user(user_id: int):
    """Delete user"""
    try:
        admin_user = require_admin()
        
        if user_id == admin_user["id"]:
            raise BadRequest("Cannot delete your own account")

        get_db().delete_user(user_id)
        logger.info(f"User {user_id} deleted by admin")
        
        return jsonify({"message": "User deleted"}), 200
    except Exception as e:
        return json_error(e)

import logging
from contextlib import contextmanager
from typing import Any, Dict, List, Optional
from sqlalchemy import create_engine, select, func
from sqlalchemy.exc import IntegrityError
from sqlalchemy.orm import sessionmaker
from models import Base, User, Client, Prediction, Log, ModelVersion
logger = logging.getLogger(__name__)

class DatabaseService:
    def __init__(self, database_url: str):
        self.engine = create_engine(database_url, future=True)
        self.SessionLocal = sessionmaker(bind=self.engine, autoflush=False, autocommit=False, future=True)
        self._migrate_sqlite()
        Base.metadata.create_all(self.engine)

    def _migrate_sqlite(self) -> None:
        if self.engine.dialect.name != "sqlite":
            return
        with self.engine.begin() as conn:
            tables = {row[0] for row in conn.exec_driver_sql("SELECT name FROM sqlite_master WHERE type='table'").fetchall()}
            if "predictions" in tables:
                cols = {row[1] for row in conn.exec_driver_sql("PRAGMA table_info(predictions)").fetchall()}
                required = {"id", "user_id", "client_id", "input_json", "prediction", "probability", "decision", "explanation", "created_at"}
                if not required.issubset(cols):
                    conn.exec_driver_sql("DROP TABLE predictions")
            if "clients" in tables:
                cols = {row[1] for row in conn.exec_driver_sql("PRAGMA table_info(clients)").fetchall()}
                required = {"id", "name", "email", "phone", "wilaya", "city", "created_at"}
                if not required.issubset(cols):
                    conn.exec_driver_sql("DROP TABLE clients")

    @contextmanager
    def session(self):
        session = self.SessionLocal()
        try:
            yield session; session.commit()
        except Exception:
            session.rollback(); raise
        finally:
            session.close()
    def get_user_by_email(self, email: str) -> Optional[Dict[str, Any]]:
        with self.session() as s:
            u=s.execute(select(User).filter_by(email=email.lower())).scalar_one_or_none()
            return None if not u else {
                "id": u.id,
                "email": u.email,
                "role": u.role,
                "password_hash": u.password_hash,
                "plan_tier": u.plan_tier,
                "subscription_status": u.subscription_status,
                "created_at": u.created_at.isoformat()
            }
    def get_user_by_id(self, user_id: int) -> Optional[Dict[str, Any]]:
        """Get user by ID."""
        with self.session() as s:
            u=s.get(User, user_id)
            return None if not u else {
                "id": u.id,
                "email": u.email,
                "role": u.role,
                "plan_tier": u.plan_tier,
                "subscription_status": u.subscription_status,
                "monthly_predictions_used": u.monthly_predictions_used,
                "created_at": u.created_at.isoformat()
            }
    def list_users(self) -> List[Dict[str, Any]]:
        with self.session() as s:
            rows=s.execute(select(User).order_by(User.created_at.asc())).scalars().all()
            return [{"id":u.id,"email":u.email,"role":u.role,"created_at":u.created_at.isoformat()} for u in rows]
    def create_user(self, email: str, password_hash: str, role: str="admin") -> Dict[str, Any]:
        with self.session() as s:
            u=User(email=email.lower(),password_hash=password_hash,role=role); s.add(u)
            try: s.flush()
            except IntegrityError as exc: raise ValueError("User already exists") from exc
            return {"id":u.id,"email":u.email,"role":u.role,"created_at":u.created_at.isoformat()}
    def verify_user_password(self,email:str)->Optional[str]:
        with self.session() as s:
            u=s.execute(select(User).filter_by(email=email.lower())).scalar_one_or_none(); return u.password_hash if u else None
    def ensure_default_admin(self,email:str,password_hash:str)->None:
        with self.session() as s:
            u=s.execute(select(User).filter_by(email=email.lower())).scalar_one_or_none()
            if u:
                u.password_hash=password_hash
                u.role="admin"
            else:
                s.add(User(email=email.lower(),password_hash=password_hash,role="admin"))
    def list_clients(self)->List[Dict[str,Any]]:
        with self.session() as s:
            rows=s.execute(select(Client).order_by(Client.created_at.desc())).scalars().all()
            return [{"id":c.id,"name":c.name,"email":c.email,"phone":c.phone,"wilaya":c.wilaya,"city":c.city,"created_at":c.created_at.isoformat()} for c in rows]
    def create_client(self,data:Dict[str,Any])->Dict[str,Any]:
        with self.session() as s:
            c=Client(name=data["name"],email=data["email"],phone=data["phone"],wilaya=data["wilaya"],city=data["city"]); s.add(c); s.flush()
            return {"id":c.id,"name":c.name,"email":c.email,"phone":c.phone,"wilaya":c.wilaya,"city":c.city,"created_at":c.created_at.isoformat()}
    def delete_client(self,client_id:int)->None:
        with self.session() as s:
            c=s.get(Client,client_id)
            if c: s.delete(c)
    def client_exists(self,client_id:int)->bool:
        with self.session() as s: return s.get(Client,client_id) is not None
    def create_prediction(self,user_id:Optional[int],input_json:Dict[str,Any],prediction:str,probability:float,decision:str,explanation:Dict[str,Any],client_id:Optional[int]=None):
        with self.session() as s: s.add(Prediction(user_id=user_id,client_id=client_id,input_json=input_json,prediction=prediction,probability=probability,decision=decision,explanation=explanation))
    def get_predictions(self,user_id:Optional[int]=None,limit:int=100)->List[Dict[str,Any]]:
        with self.session() as s:
            q=select(Prediction).order_by(Prediction.created_at.desc()).limit(limit)
            if user_id is not None: q=q.filter_by(user_id=user_id)
            rows=s.execute(q).scalars().all()
            return [{"id":p.id,"user_id":p.user_id,"client_id":p.client_id,"input_json":p.input_json,"prediction":p.prediction,"probability":p.probability,"decision":p.decision,"explanation":p.explanation,"created_at":p.created_at.isoformat()} for p in rows]
    def get_analytics(self)->Dict[str,Any]:
        with self.session() as s:
            total=s.execute(select(func.count(Prediction.id))).scalar_one() or 0
            avg=s.execute(select(func.avg(Prediction.probability))).scalar_one() or 0.0
            dist=s.execute(select(Prediction.prediction,func.count(Prediction.id)).group_by(Prediction.prediction)).all()
            dialect=s.bind.dialect.name
            month_expr=func.strftime('%Y-%m', Prediction.created_at) if dialect=="sqlite" else func.to_char(Prediction.created_at,'YYYY-MM')
            monthly=s.execute(select(month_expr,func.count(Prediction.id)).group_by(month_expr).order_by(month_expr)).all()
            return {"total_predictions":int(total),"average_probability":float(avg),"risk_distribution":{r[0]:int(r[1]) for r in dist},"monthly_predictions":[{"month":r[0],"count":int(r[1])} for r in monthly]}
    def log_action(self,action:str,level:str="info",details:Optional[Dict[str,Any]]=None):
        with self.session() as s: s.add(Log(action=action,level=level,details=details or {}))
    def create_model_version(self,version:str,metrics:Dict[str,Any]):
        with self.session() as s: s.add(ModelVersion(version=version,metrics=metrics))
    def get_user_model_by_email(self, email: str) -> Optional[User]:
        """Get user object by email (for Stripe operations)."""
        with self.session() as s:
            return s.execute(select(User).filter_by(email=email.lower())).scalar_one_or_none()
    def update_user_subscription(
        self,
        user_id: int,
        subscription_status: str = None,
        plan_tier: str = None,
        stripe_customer_id: str = None,
        stripe_subscription_id: str = None,
        subscription_expires_at = None,
    ) -> bool:
        """Update user subscription fields after payment."""
        with self.session() as s:
            user = s.get(User, user_id)
            if not user:
                return False
            if subscription_status:
                user.subscription_status = subscription_status
            if plan_tier:
                user.plan_tier = plan_tier
            if stripe_customer_id:
                user.stripe_customer_id = stripe_customer_id
            if stripe_subscription_id:
                user.stripe_subscription_id = stripe_subscription_id
            if subscription_expires_at:
                user.subscription_expires_at = subscription_expires_at
            return True

    def check_prediction_limit(self, user_id: int) -> Dict[str, Any]:
        """Check if user has reached their prediction limit for the month."""
        from datetime import datetime, timedelta
        with self.session() as s:
            user = s.get(User, user_id)
            if not user:
                return {"allowed": True, "remaining": None, "limit_reached": False}
            
            # Only free plan has limits
            if user.plan_tier != "free":
                return {"allowed": True, "remaining": None, "limit_reached": False}
            
            # Check if we need to reset the monthly counter (new month)
            now = datetime.utcnow()
            if user.predictions_month_reset is None or user.predictions_month_reset < now:
                user.monthly_predictions_used = 0
                user.predictions_month_reset = datetime(now.year, now.month, 1) + timedelta(days=32)
                user.predictions_month_reset = user.predictions_month_reset.replace(day=1)  # First day of next month
                s.commit()
            
            limit = 100
            remaining = max(0, limit - user.monthly_predictions_used)
            limit_reached = user.monthly_predictions_used >= limit
            
            return {
                "allowed": not limit_reached,
                "remaining": remaining,
                "limit_reached": limit_reached,
                "used": user.monthly_predictions_used,
                "limit": limit
            }

    def track_prediction(self, user_id: int) -> bool:
        """Increment prediction count for the month."""
        with self.session() as s:
            user = s.get(User, user_id)
            if not user:
                return False
            user.monthly_predictions_used += 1
            s.commit()
            return True
    
    def update_user_role(self, user_id: int, role: str) -> bool:
        """Update user role."""
        with self.session() as s:
            user = s.get(User, user_id)
            if not user:
                return False
            user.role = role
            s.commit()
            return True
    
    def update_user_plan(self, user_id: int, plan_tier: str) -> bool:
        """Update user plan tier."""
        with self.session() as s:
            user = s.get(User, user_id)
            if not user:
                return False
            user.plan_tier = plan_tier
            s.commit()
            return True
    
    def delete_user(self, user_id: int) -> bool:
        """Delete user."""
        with self.session() as s:
            user = s.get(User, user_id)
            if not user:
                return False
            s.delete(user)
            s.commit()
            return True
    
    def fetch_predictions(self, user_id: int = None, limit: int = 100) -> List[Dict[str, Any]]:
        """Fetch predictions for user (alias for get_predictions)."""
        return self.get_predictions(user_id, limit)
    
    def fetch_analytics(self) -> Dict[str, Any]:
        """Fetch analytics (alias for get_analytics)."""
        return self.get_analytics()
    
    def fetch_logs(self, limit: int = 100) -> List[Dict[str, Any]]:
        """Fetch logs."""
        with self.session() as s:
            rows = s.execute(select(Log).order_by(Log.created_at.desc()).limit(limit)).scalars().all()
            return [{"action": l.action, "level": l.level, "details": l.details, "created_at": l.created_at.isoformat()} for l in rows]
    
    def log_prediction(self, user_id: int, input_json: Dict[str, Any], prediction: str, probability: float, decision: str, explanation: Dict[str, Any] = None, client_id: int = None):
        """Log prediction (alias for create_prediction)."""
        self.create_prediction(user_id, input_json, prediction, probability, decision, explanation or {}, client_id)

import json
import logging
from datetime import datetime
from typing import Any, Dict, List, Optional

from sqlalchemy import JSON, Column, DateTime, Float, Integer, String, Text, create_engine, func, text
from sqlalchemy.exc import IntegrityError
from sqlalchemy.orm import Session, declarative_base, sessionmaker
from supabase import Client, create_client

from config.config import settings

logger = logging.getLogger(__name__)
Base = declarative_base()


class User(Base):
    __tablename__ = "users"
    id = Column(Integer, primary_key=True, autoincrement=True)
    email = Column(String(256), unique=True, nullable=False)
    password_hash = Column(Text, nullable=False)
    role = Column(String(50), nullable=False, default="user")
