@api_bp.route("/predict",methods=["POST"])
def predict():
    try:
        user_email=require_auth(); data=parse_request_json(request); validated=validate_json_payload(data); client_id=validated.pop("client_id",None)
        dbs=get_db_service()
        if client_id is None or not dbs.client_exists(client_id): raise BadRequest("A real client_id is required")
        
        # Check prediction limit for free plan users
        user=dbs.get_user_by_email(user_email)
        if user:
            limit_check = dbs.check_prediction_limit(user.id)
            if not limit_check["allowed"]:
                return jsonify({
                    "error": "Prediction limit reached",
                    "message": "You have reached your monthly limit of 100 predictions on the free plan",
                    "used": limit_check["used"],
                    "limit": limit_check["limit"],
                    "upgrade_prompt": True
                }), 429
        
        cached=get_cache_client().get_prediction(validated)
        if cached: return jsonify(cached),200
        result=get_ml_service().predict(validated); get_cache_client().set_prediction(validated,result)
        
        # Track the prediction
        if user:
            dbs.track_prediction(user.id)
            dbs.create_prediction(user.id, {**validated,"client_id":client_id}, result["prediction"], result["probability"], result["decision"], result.get("explanation",{}), client_id=client_id)
        else:
            dbs.create_prediction(None, {**validated,"client_id":client_id}, result["prediction"], result["probability"], result["decision"], result.get("explanation",{}), client_id=client_id)
        
        return jsonify(result),200
    except Exception as e: return jsonify({"error":str(e) if isinstance(e,(BadRequest,ValueError,RuntimeError)) else "Internal server error"}),400 if isinstance(e,(BadRequest,ValueError,RuntimeError)) else 500
