import stripe
import hmac
import hashlib
import json
from flask import Blueprint, request, jsonify
from werkzeug.exceptions import BadRequest, Unauthorized
from auth.jwt import JWTService
from services.db import DatabaseService
from services.payment_service import PaymentService
from config.config import settings

payment_bp = Blueprint("payment", __name__)

def get_db_service():
    return DatabaseService(settings.DATABASE_URL)

def require_auth():
    """Extract user email from JWT token."""
    auth_header = request.headers.get("Authorization", "")
    if not auth_header.startswith("Bearer "):
        raise Unauthorized("Missing or invalid token")
    payload = JWTService.decode_access_token(auth_header.split(" ", 1)[1])
    if not payload:
        raise Unauthorized("Invalid or expired token")
    return payload["sub"]  # Returns user email


@payment_bp.route("/create-checkout-session", methods=["POST"])
def create_checkout_session():
    """
    Create a Stripe checkout session.
    
    Request body:
    {
        "plan_id": "pro" | "enterprise",
        "language": "en" | "fr" | "ar",
        "return_url": "optional custom URL"
    }
    """
    try:
        user_email = require_auth()
        data = request.get_json()
        
        if not data:
            raise BadRequest("Request body is required")
        
        plan_id = data.get("plan_id")
        language = data.get("language", "en")
        return_url = data.get("return_url")
        
        if not plan_id:
            raise BadRequest("plan_id is required")
        
        if plan_id not in ["pro", "enterprise"]:
            raise BadRequest("Invalid plan_id")
        
        if language not in ["en", "fr", "ar"]:
            language = "en"
        
        # Create checkout session via PaymentService
        result = PaymentService.create_checkout_session(
            user_email=user_email,
            plan_id=plan_id,
            language=language,
            return_url=return_url,
        )
        
        return jsonify(result), 200
    
    except Unauthorized as e:
        return jsonify({"error": str(e)}), 401
    except BadRequest as e:
        return jsonify({"error": str(e)}), 400
    except ValueError as e:
        return jsonify({"error": str(e)}), 400
    except Exception as e:
        print(f"Error creating checkout session: {str(e)}")
        return jsonify({"error": "Internal server error"}), 500


@payment_bp.route("/webhook/stripe", methods=["POST"])
def stripe_webhook():
    """
    Handle Stripe webhook events.
    Verify webhook signature and process:
    - checkout.session.completed
    - customer.subscription.updated
    - customer.subscription.deleted
    """
    try:
        payload = request.get_data(as_text=True)
        sig_header = request.headers.get("Stripe-Signature")
        
        if not sig_header:
            raise BadRequest("Missing Stripe-Signature header")
        
        webhook_secret = settings.STRIPE_WEBHOOK_SECRET
        if not webhook_secret:
            print("Warning: STRIPE_WEBHOOK_SECRET not configured")
            # In development, accept webhook without verification
            event = json.loads(payload)
        else:
            try:
                event = stripe.Webhook.construct_event(
                    payload, sig_header, webhook_secret
                )
            except ValueError:
                raise BadRequest("Invalid payload")
            except stripe.error.SignatureVerificationError:
                raise BadRequest("Invalid signature")
        
        db = get_db_service()
        event_type = event.get("type")
        event_data = event.get("data", {}).get("object", {})
        
        print(f"Processing Stripe webhook: {event_type}")
        
        if event_type == "checkout.session.completed":
            session_id = event_data.get("id")
            success = PaymentService.handle_checkout_session_completed(
                session_id, db
            )
            if not success:
                print(f"Failed to complete checkout session: {session_id}")
                return jsonify({"error": "Failed to process checkout"}), 400
        
        elif event_type == "customer.subscription.updated":
            subscription_id = event_data.get("id")
            success = PaymentService.handle_customer_subscription_updated(
                subscription_id, db
            )
            if not success:
                print(f"Failed to update subscription: {subscription_id}")
        
        elif event_type == "customer.subscription.deleted":
            subscription_id = event_data.get("id")
            success = PaymentService.handle_customer_subscription_deleted(
                subscription_id, db
            )
            if not success:
                print(f"Failed to delete subscription: {subscription_id}")
        
        return jsonify({"ok": True}), 200
    
    except BadRequest as e:
        return jsonify({"error": str(e)}), 400
    except Exception as e:
        print(f"Error processing webhook: {str(e)}")
        return jsonify({"error": "Internal server error"}), 500


