            return lang_responses.get("pricing", lang_responses["default"])
        elif any(
            keyword in message_lower
            for keyword in ["upload", "csv", "file", "import", "batch"]
        ):
            return lang_responses.get("upload", lang_responses["default"])
        elif any(
            keyword in message_lower
            for keyword in ["risk", "prediction", "score", "probability", "decision"]
        ):
            return lang_responses.get("risk", lang_responses["default"])

        return lang_responses["default"]

import json, hashlib, logging
from typing import Any, Dict, Optional
import redis
logger=logging.getLogger(__name__)
class CacheClient:
    def __init__(self, redis_url: str):
        self.client=None
        if redis_url:
            try:
                self.client=redis.from_url(redis_url, decode_responses=True)
                self.client.ping()
            except Exception:
                logger.warning("redis_unavailable_cache_disabled")
                self.client=None
    def build_key(self,prefix:str,payload:Dict[str,Any])->str:
        return f"{prefix}:{hashlib.sha256(json.dumps(payload,sort_keys=True).encode()).hexdigest()}"
    def get_prediction(self,payload:Dict[str,Any])->Optional[Dict[str,Any]]:
        if not self.client: return None
        raw=self.client.get(self.build_key("prediction",payload)); return json.loads(raw) if raw else None
    def set_prediction(self,payload:Dict[str,Any],result:Dict[str,Any],ttl:int=3600)->None:
        if self.client: self.client.set(self.build_key("prediction",payload),json.dumps(result),ex=ttl)
    def save_batch_result(self,batch_id:str,records:Dict[str,Any],ttl:int=3600)->None:
        if self.client: self.client.set(f"batch:{batch_id}",json.dumps(records),ex=ttl)
    def get_batch_result(self,batch_id:str)->Optional[Dict[str,Any]]:
        if not self.client: return None
        raw=self.client.get(f"batch:{batch_id}"); return json.loads(raw) if raw else None

import re
from typing import Any, Dict, List
from flask import Request
REQUIRED_FEATURES = ["loan_amnt","annual_inc","dti","fico_range_high","revol_util","open_acc","total_acc","inq_last_6mths","delinq_2yrs","acc_now_delinq"]
def validate_json_payload(payload: Dict[str, Any], required_fields: List[str] = None) -> Dict[str, Any]:
    required_fields = required_fields or REQUIRED_FEATURES
    missing=[f for f in required_fields if f not in payload]
    if missing: raise ValueError(f"Missing required fields: {', '.join(missing)}")
    cleaned={f: float(payload[f]) for f in required_fields}
    if "client_id" in payload: cleaned["client_id"] = int(payload["client_id"])
    return cleaned
def parse_request_json(request: Request) -> Dict[str, Any]:
    data=request.get_json(force=True,silent=True)
    if not data: raise ValueError("Invalid or missing JSON payload")
    return data
def validate_phone_format(phone:str)->bool:
    return re.match(r"^(\+213|0|00)(5|6|7|1|2|3)[0-9]{8,12}$", re.sub(r"[\s-]", "", phone or "")) is not None

"use client"
import * as React from "react"
import { flushSync } from "react-dom"
import { useRouter } from "next/navigation"
import { api, ApiUser, clearToken, getToken, getRefreshToken, setToken, setRefreshToken } from "../lib/api"


type AuthContextType = {
  user: ApiUser | null
  loading: boolean
  login: (email: string, password: string) => Promise<void>
  logout: () => void
  refresh: () => Promise<void>
}
const AuthContext = React.createContext<AuthContextType | undefined>(undefined)

export function AuthProvider({ children }: { children: React.ReactNode }) {
  const [user, setUser] = React.useState<ApiUser | null>(null)
  const [loading, setLoading] = React.useState(true)
  const router = useRouter()

  const refresh = React.useCallback(async () => {
    console.log("🔄 [AUTH] Session refresh starting...")
    try {
      const token = getToken()
      const refreshToken = getRefreshToken()

      if (!token && !refreshToken) {
        console.log("🔄 [AUTH] No session tokens available")
        setUser(null)
        setLoading(false)
        return
      }

      const cached = localStorage.getItem("paypredict.user")
      if (cached) {
        setUser(JSON.parse(cached))
      }

      try {
        console.log("🔄 [AUTH] Verifying access token with /auth/me...")
        const res = await api.me()
        setUser(res.user)
        localStorage.setItem("paypredict.user", JSON.stringify(res.user))
        console.log("✅ [AUTH] Access token validated")
        return
      } catch (error: any) {
        if (!refreshToken) {
          throw error
        }
        console.log("🔄 [AUTH] Access token invalid; attempting refresh...")
      }

      const refreshRes = await api.refresh()
      setToken(refreshRes.token)
      if (refreshRes.refresh_token) {
        setRefreshToken(refreshRes.refresh_token)
      }

      const me = await api.me()
      setUser(me.user)
      localStorage.setItem("paypredict.user", JSON.stringify(me.user))
      console.log("✅ [AUTH] Session refreshed successfully")
    } catch (e: any) {
      if (e?.message?.includes("401") || e?.message?.includes("Unauthorized")) {
        console.log("🔄 [AUTH] Session expired or invalid")
      } else {
        console.error("❌ [AUTH] Session refresh failed:", e)
      }
      clearToken()
      setUser(null)
    } finally {
      setLoading(false)
    }
  }, [])

  React.useEffect(() => {
    refresh()
  }, [refresh])

  const login = async (email: string, password: string) => {
    setLoading(true)
    try {
      const res = await api.login(email, password)
      const token = res.token
      const refreshToken = res.refresh_token
      const userData = res.user

      setToken(token)
      if (refreshToken) {
        setRefreshToken(refreshToken)
      }

      // Create the cookie expected by Next middleware/route proxy.
      // (The UI guard relies on `user`, while dashboard routes proxy checks `paypredict.session`.)
      if (typeof document !== "undefined") {
        document.cookie = "paypredict.session=1; path=/; max-age=3600; SameSite=Lax"
      }

      localStorage.setItem("paypredict.user", JSON.stringify(userData))

      flushSync(() => {
        setUser(userData)
        setLoading(false)
      })

      try {
        await router.replace("/dashboard")
      } catch (navigationError) {
        console.error("❌ [AUTH] Navigation error:", navigationError)
        setLoading(false)
        throw navigationError
      }
    } catch (err) {
      console.error("❌ [AUTH] Login error:", err)
      // Ensure stale session cookie is removed.
      if (typeof document !== "undefined") {
        document.cookie = "paypredict.session=; path=/; max-age=0; SameSite=Lax"
      }
      setLoading(false)
      throw err
    }
  }


  const logout = () => {
    clearToken()
    setUser(null)
    router.push("/login")
  }

  return <AuthContext.Provider value={{ user, loading, login, logout, refresh }}>{children}</AuthContext.Provider>
}

export function useAuth() {
  const ctx = React.useContext(AuthContext)
  if (!ctx) throw new Error("useAuth must be used within AuthProvider")
  return ctx
}

export function AuthGuard({ children }: { children: React.ReactNode }) {
  const { user, loading } = useAuth()
  const router = useRouter()

  React.useEffect(() => {
    if (!loading && !user) {
      router.replace("/login")
    }
  }, [loading, user, router])

  if (loading) {
    return <div className="min-h-screen grid place-items-center text-sm text-muted-foreground">Loading session...</div>
  }

  if (!user) {
    return null
  }

  return <>{children}</>
}

import datetime
from typing import Dict, Optional

import jwt

from config.config import settings

class JWTService:
    ACCESS_EXPIRES_MINUTES = 60
    REFRESH_EXPIRES_MINUTES = 60 * 24 * 7

    @staticmethod
    def create_access_token(subject: str, expires_minutes: int = ACCESS_EXPIRES_MINUTES) -> str:
        now = datetime.datetime.utcnow()
        payload = {
            "sub": subject,
            "iat": now,
            "exp": now + datetime.timedelta(minutes=expires_minutes),
            "scope": "access",
        }
        return jwt.encode(payload, settings.JWT_SECRET, algorithm="HS256")

    @staticmethod
    def create_refresh_token(subject: str, expires_minutes: int = REFRESH_EXPIRES_MINUTES) -> str:
        now = datetime.datetime.utcnow()
        payload = {
            "sub": subject,
            "iat": now,
            "exp": now + datetime.timedelta(minutes=expires_minutes),
            "scope": "refresh",
        }
        return jwt.encode(payload, settings.JWT_SECRET, algorithm="HS256")

    @staticmethod
    def decode_access_token(token: str) -> Optional[Dict[str, any]]:
        payload = JWTService._decode(token)
        if payload and payload.get("scope") == "access":
            return payload
        return None

    @staticmethod
    def decode_refresh_token(token: str) -> Optional[Dict[str, any]]:
        payload = JWTService._decode(token)
        if payload and payload.get("scope") == "refresh":
            return payload
        return None

    @staticmethod
    def _decode(token: str) -> Optional[Dict[str, any]]:
        try:
            return jwt.decode(token, settings.JWT_SECRET, algorithms=["HS256"])
        except jwt.ExpiredSignatureError:
            return None
        except jwt.InvalidTokenError:
            return None

