import datetime
from typing import Dict, Optional

import jwt

from config.config import settings

class JWTService:
    ACCESS_EXPIRES_MINUTES = 60
    REFRESH_EXPIRES_MINUTES = 60 * 24 * 7

    @staticmethod
    def create_access_token(subject: str, expires_minutes: int = ACCESS_EXPIRES_MINUTES) -> str:
        now = datetime.datetime.utcnow()
        payload = {
            "sub": subject,
            "iat": now,
            "exp": now + datetime.timedelta(minutes=expires_minutes),
            "scope": "access",
        }
        return jwt.encode(payload, settings.JWT_SECRET, algorithm="HS256")

    @staticmethod
    def create_refresh_token(subject: str, expires_minutes: int = REFRESH_EXPIRES_MINUTES) -> str:
        now = datetime.datetime.utcnow()
        payload = {
            "sub": subject,
            "iat": now,
            "exp": now + datetime.timedelta(minutes=expires_minutes),
            "scope": "refresh",
        }
        return jwt.encode(payload, settings.JWT_SECRET, algorithm="HS256")

    @staticmethod
    def decode_access_token(token: str) -> Optional[Dict[str, any]]:
        payload = JWTService._decode(token)
        if payload and payload.get("scope") == "access":
            return payload
        return None

    @staticmethod
    def decode_refresh_token(token: str) -> Optional[Dict[str, any]]:
        payload = JWTService._decode(token)
        if payload and payload.get("scope") == "refresh":
            return payload
        return None

    @staticmethod
    def _decode(token: str) -> Optional[Dict[str, any]]:
        try:
            return jwt.decode(token, settings.JWT_SECRET, algorithms=["HS256"])
        except jwt.ExpiredSignatureError:
            return None
        except jwt.InvalidTokenError:
            return None

