interface AdminStats {
  total_users: number
  total_clients: number
  total_predictions: number
  active_subscriptions: number
  monthly_revenue: number
  high_risk_cases: number
}

interface RecentActivity {
  id: number
  user_email: string
  action: string
  timestamp: string
}

export default function AdminDashboard() {
  const { t } = useLanguage()
  const [stats, setStats] = useState<AdminStats | null>(null)
  const [recentActivity, setRecentActivity] = useState<RecentActivity[]>([])
  const [users, setUsers] = useState<any[]>([])
  const [loading, setLoading] = useState(true)

  useEffect(() => {
    fetchAdminData()
  }, [])

  const fetchAdminData = async () => {
    try {
      setLoading(true)
      // Fetch analytics for overview
      const analyticsData = await api.analytics()
      
      // Fetch users list
      try {
        const usersData = await (api as any).listAdmins?.()
        setUsers(usersData?.admins || [])
      } catch (e) {
        // Fallback: show empty users
        console.warn("Could not fetch users list")
      }

      setStats({
        total_users: users.length + 1,
        total_clients: 0,
        total_predictions: analyticsData?.total_predictions || 0,
        active_subscriptions: 0,
        monthly_revenue: 0,
        high_risk_cases: analyticsData?.risk_distribution?.high_risk || 0,
      })
    } catch (error: any) {
      toast.error("Failed to load admin dashboard")
      console.error(error)
    } finally {
      setLoading(false)
    }
  }

  if (loading) {
    return (
      <div className="flex items-center justify-center min-h-[400px]">
        <div className="text-center">
          <div className="w-12 h-12 rounded-full border-2 border-primary border-t-transparent animate-spin mx-auto" />
          <p className="mt-4 text-sm text-muted-foreground">Loading admin dashboard...</p>
        </div>
      </div>
    )
  }

  return (
    <div className="space-y-8">
      <PageHeader
        title={t("dashboard.admin.title") || "Admin Dashboard"}
        description={t("dashboard.admin.description") || "Manage users, subscriptions, and system health"}
        actions={
          <Button variant="outline" className="gap-2">
            <Download className="size-4" />
            Export Report
          </Button>
        }
      />

      {/* KPI CARDS */}
      <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-4">
        <StatCard
          title="Total Users"
          value={stats?.total_users || 0}
          description={t("dashboard.admin.stats.users") || "Active users on platform"}
          icon={Users}
          trend={{ value: 12, positive: true }}
        />
        <StatCard
          title="Predictions"
          value={stats?.total_predictions || 0}
          description="This month"
          icon={TrendingUp}
          trend={{ value: 8, positive: true }}
        />
        <StatCard
          title="High Risk Cases"
          value={stats?.high_risk_cases || 0}
          description="Flagged for review"
          icon={AlertCircle}
          trend={{ value: 3, positive: false }}
        />
        <StatCard
          title="System Health"
          value="99.9%"
          description="Uptime last 30 days"
          icon={CheckCircle2}
          trend={{ value: 0, positive: true }}
        />
      </div>

      <div className="grid gap-6 lg:grid-cols-3">
        {/* USERS MANAGEMENT */}
        <Card className="lg:col-span-2">
          <CardHeader>
            <div className="flex items-center justify-between">
              <div>
                <CardTitle>Users</CardTitle>
                <CardDescription>Manage platform users and roles</CardDescription>
              </div>
              <Link href="/dashboard/admins">
                <Button size="sm" variant="outline">View All</Button>
              </Link>
            </div>
          </CardHeader>
          <CardContent>
            <div className="space-y-3">
              {users.length === 0 ? (
                <p className="text-sm text-muted-foreground text-center py-6">No users yet</p>
              ) : (
                users.slice(0, 5).map((user) => (
                  <div key={user.id} className="flex items-center justify-between p-3 border rounded-lg">
                    <div className="flex-1">
                      <p className="font-medium text-sm">{user.email}</p>
                      <p className="text-xs text-muted-foreground">{user.role}</p>
                    </div>
                    <Badge variant={user.role === "admin" ? "default" : "secondary"}>
                      {user.role}
                    </Badge>
                  </div>
                ))
              )}
            </div>
          </CardContent>
        </Card>

        {/* QUICK ACTIONS */}
        <Card>
          <CardHeader>
            <CardTitle>Quick Actions</CardTitle>
            <CardDescription>Common admin tasks</CardDescription>
          </CardHeader>
          <CardContent className="space-y-2">
            <Link href="/dashboard/admins" className="block">
              <Button variant="outline" className="w-full justify-start" size="sm">
                <Users className="size-4 mr-2" />
                Manage Admins
              </Button>
            </Link>
            <Link href="/dashboard/analytics" className="block">
              <Button variant="outline" className="w-full justify-start" size="sm">
                <BarChart3 className="size-4 mr-2" />
                Analytics
              </Button>
            </Link>
            <Link href="/dashboard/clients" className="block">
              <Button variant="outline" className="w-full justify-start" size="sm">
                <Activity className="size-4 mr-2" />
                View Clients
              </Button>
            </Link>
            <Button variant="outline" className="w-full justify-start" size="sm" onClick={() => window.open("/api/logs")}>
              <Eye className="size-4 mr-2" />
              System Logs
            </Button>
          </CardContent>
        </Card>
      </div>

      {/* RECENT ACTIVITY */}
      <Card>
        <CardHeader>
          <CardTitle>Recent Activity</CardTitle>
          <CardDescription>System events and user actions</CardDescription>
        </CardHeader>
        <CardContent>
          <div className="space-y-3">
            {[...Array(5)].map((_, i) => (
              <div key={i} className="flex items-start gap-3 pb-3 border-b last:border-0 last:pb-0">
                <Clock className="size-4 mt-0.5 text-muted-foreground flex-shrink-0" />
                <div className="flex-1 min-w-0">
