    e.preventDefault()
    setFormError("")

    const form = new FormData(e.currentTarget)
    const email = String(form.get("email") || "").trim()
    const password = String(form.get("password") || "")

    if (!email || !password) {
      setFormError(t("auth.required"))
      toast.error(t("auth.required"))
      return
