import * as React from "react"
import Link from "next/link"
import { usePathname } from "next/navigation"
import { motion, AnimatePresence } from "framer-motion"
import {
  LayoutDashboard,
  Sparkles,
  Upload,
  BarChart3,
  Users,
  ShieldCheck,
  CreditCard,
  Settings,
  HelpCircle,
  ChevronsLeft,
