      label: t("nav.account"),
      items: [
        { href: "/dashboard/profile", label: t("nav.profile"), icon: Users },
        { href: "/dashboard/settings", label: t("nav.settings"), icon: Settings },
      ],
    },
  ]

  // Filter nav groups by user role
  const navGroups = allNavGroups
    .map(group => ({
      ...group,
      items: group.items.filter(item => !item.roles || item.roles.includes(userRole as "admin" | "client")),
    }))
    .filter(group => group.items.length > 0)

  const SidebarInner = (
    <div className="flex h-full flex-col text-sidebar-foreground">
      <div
        className={cn(
          "flex h-16 items-center border-b border-sidebar-border px-4",
          collapsed ? "justify-center" : "justify-between",
        )}
      >
        {collapsed ? (
          <Logo showWordmark={false} />
        ) : (
          <Link href="/" className="flex items-center">
            <Logo variant="light" />
          </Link>
        )}
        <button
          onClick={() => setCollapsed((v) => !v)}
          className="hidden rounded-md p-1.5 text-sidebar-foreground/70 hover:bg-sidebar-accent hover:text-sidebar-foreground lg:flex"
          aria-label="Collapse sidebar"
        >
          <ChevronsLeft
            className={cn(
              "size-4 transition-transform",
              collapsed && "rotate-180",
            )}
          />
        </button>
        <button
          onClick={onMobileClose}
          className="rounded-md p-1.5 hover:bg-sidebar-accent lg:hidden"
          aria-label="Close menu"
        >
          <X className="size-4" />
        </button>
      </div>

      <nav className="flex-1 space-y-6 overflow-y-auto px-3 py-5">
        {navGroups.map((group) => (
          <div key={group.label}>
            {!collapsed && (
              <p className="mb-2 px-2 text-[10px] font-semibold uppercase tracking-[0.14em] text-sidebar-foreground/45">
                {group.label}
              </p>
            )}
            <ul className="space-y-0.5">
              {group.items.map((item) => {
                const Icon = item.icon
                const active =
                  pathname === item.href ||
                  (item.href !== "/dashboard" && pathname.startsWith(item.href))
                return (
                  <li key={item.href}>
                    <Link
                      href={item.href}
                      onClick={onMobileClose}
                      className={cn(
                        "group relative flex items-center gap-3 rounded-lg px-2.5 py-2 text-sm transition-colors",
                        active
                          ? "bg-sidebar-accent font-semibold text-sidebar-foreground"
                          : "text-sidebar-foreground/70 hover:bg-sidebar-accent/50 hover:text-sidebar-foreground",
                      )}
                    >
                      {active && (
                        <motion.span
                          layoutId="active-pill"
                          className={cn(
                            "absolute top-1.5 bottom-1.5 w-0.5 bg-[#F1B24A]",
                            isRTL ? "right-0 rounded-l" : "left-0 rounded-r",
                          )}
                        />
                      )}
                      <Icon
                        className={cn(
                          "size-4 shrink-0",
                          active && "text-[#F1B24A]",
                        )}
                      />
                      <AnimatePresence initial={false}>
                        {!collapsed && (
                          <motion.span
                            initial={{ opacity: 0, width: 0 }}
                            animate={{ opacity: 1, width: "auto" }}
                            exit={{ opacity: 0, width: 0 }}
                            className="flex-1 overflow-hidden whitespace-nowrap"
                          >
                            {item.label}
                          </motion.span>
                        )}
                      </AnimatePresence>
                      {!collapsed && item.badge && (
                        <span className="rounded-md bg-[#F1B24A] px-1.5 py-0.5 text-[10px] font-bold text-[#164A41]">
                          {item.badge}
                        </span>
                      )}
                    </Link>
                  </li>
                )
              })}
            </ul>
          </div>
        ))}
      </nav>

      {!collapsed && (
        <div className="border-t border-sidebar-border p-3">
          <div className="rounded-xl border border-[#F1B24A]/20 bg-gradient-to-br from-[#F1B24A]/15 to-[#F1B24A]/5 p-3.5">
            <div className="mb-1.5 flex items-center gap-2">
              <div className="flex size-7 items-center justify-center rounded-lg bg-[#F1B24A] text-[#164A41]">
                <Sparkles className="size-3.5" />
              </div>
              <p className="text-xs font-semibold text-sidebar-foreground">
                {t("billing.upgrade")}
              </p>
            </div>
            <p className="text-xs leading-relaxed text-sidebar-foreground/65">
              {t("billing.upgradeDesc")}
            </p>
            <Link
              href="/dashboard/subscriptions"
              className="mt-3 block w-full rounded-lg bg-[#F1B24A] py-2 text-center text-xs font-semibold text-[#164A41] transition-colors hover:bg-[#F1B24A]/90"
            >
              {t("billing.upgradeBtn")}
            </Link>
          </div>
          <Link
            href="/dashboard/help"
            className="mt-3 flex w-full items-center gap-2 rounded-lg px-2.5 py-2 text-xs text-sidebar-foreground/60 hover:bg-sidebar-accent/50 hover:text-sidebar-foreground"
          >
            <HelpCircle className="size-4" />
            {t("nav.helpDoc")}
          </Link>
        </div>
      )}
    </div>
  )

  return (
    <>
      <aside
        className={cn(
          "fixed inset-y-0 left-0 z-30 hidden border-r border-sidebar-border bg-sidebar transition-[width] duration-300 lg:flex",
          collapsed ? "w-[72px]" : "w-64",
        )}
      >
        {SidebarInner}
      </aside>

      <AnimatePresence>
        {mobileOpen && (
          <>
            <motion.div
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              exit={{ opacity: 0 }}
              className="fixed inset-0 z-40 bg-black/40 backdrop-blur-sm lg:hidden"
              onClick={onMobileClose}
            />
            <motion.aside
              initial={{ x: isRTL ? "100%" : "-100%" }}
              animate={{ x: 0 }}
              exit={{ x: isRTL ? "100%" : "-100%" }}
              transition={{ type: "spring", damping: 28, stiffness: 280 }}
              className={cn(
                "fixed inset-y-0 z-50 w-72 border-r border-sidebar-border bg-sidebar lg:hidden",
                isRTL ? "right-0" : "left-0",
              )}
            >
              {SidebarInner}
            </motion.aside>
          </>
        )}
      </AnimatePresence>
    </>
  )
}

export const SIDEBAR_DESKTOP_WIDTH_CLASS = "lg:pl-64"

"use client"

import * as React from "react"
import { useAuth } from "@/contexts/auth-context"
import { useRouter } from "next/navigation"
import AdminDashboard from "./admin-dashboard"
import ClientDashboard from "./client-dashboard"

export default function DashboardOverviewPage() {
  const { user, loading } = useAuth()
  const router = useRouter()

  if (loading) {
    return (
      <div className="flex items-center justify-center min-h-screen">
        <div className="text-center">
          <div className="w-12 h-12 rounded-full border-2 border-primary border-t-transparent animate-spin mx-auto" />
          <p className="mt-4 text-sm text-muted-foreground">Loading dashboard...</p>
        </div>
      </div>
    )
  }

  // ADMIN VIEW
  if (user?.role === "admin") {
    return <AdminDashboard />
  }

  // CLIENT VIEW (default for 'client' or unspecified roles)
  if (user?.role === "client") {
    return <ClientDashboard />
  }

  // Fallback: redirect to login if role not recognized
  return (
    <div className="flex items-center justify-center min-h-screen">
      <div className="text-center">
        <p className="text-red-500">Invalid user role. Please log in again.</p>
        <button
          onClick={() => router.push("/login")}
          className="mt-4 text-primary hover:underline"
        >
          Return to login
        </button>
      </div>
    </div>
  )
}
